#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int A[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        qsort(A, N, sizeof(int), compare);
        long long count = 0;
        for (int mask = 1; mask < (1 << N); mask++) {
            int sub[N];
            int size = 0;
            for (int i = 0; i < N; i++) {
                if ((mask & (1 << i)) != 0) {
                    sub[size++] = A[i];
                }
            }
            int median;
            if (size % 2 == 1) {
                median = sub[size / 2];
            } else {
                median = (sub[size / 2 - 1] + sub[size / 2]) / 2;
            }
            int found = 0;
            for (int i = 0; i < size; i++) {
                if (sub[i] == median) {
                    found = 1;
                    break;
                }
            }
            if (found) {
                count++;
            }
        }
        printf("%lld\n", count % MOD);
    }
    return 0;
}

