// COMPLETE, RUNNABLE JavaScript code
const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const MOD = 1000000007;

function nextInt() {
    return parseInt(lines[idx++]);
}

function nextIntArray() {
    return lines[idx++].split(' ').map(x => parseInt(x));
}

let T = nextInt();
while (T-- > 0) {
    let N = nextInt();
    let A = nextIntArray();
    A.sort((a, b) => a - b);
    let count = 0;
    for (let mask = 1; mask < (1 << N); mask++) {
        let sub = [];
        for (let i = 0; i < N; i++) {
            if ((mask & (1 << i)) !== 0) {
                sub.push(A[i]);
            }
        }
        let median;
        if (sub.length % 2 === 1) {
            median = sub[Math.floor(sub.length / 2)];
        } else {
            median = Math.floor((sub[sub.length / 2 - 1] + sub[sub.length / 2]) / 2);
        }
        if (sub.includes(median)) {
            count++;
        }
    }
    console.log(count % MOD);
}

